    private SOAPMessage handleImportData(Node operationNode) throws Exception {
        ImportRequest importRequest = parseImportRequest(operationNode);

        LOGGER.info("Importing data for entity: " + importRequest.getEntityName()
                + ", records: " + importRequest.getRecords().size());

        List<Map<String, String>> existingData = dataStore.computeIfAbsent(
                importRequest.getEntityName(), k -> Collections.synchronizedList(new ArrayList<>()));

        int importedCount = 0;
        List<String> errors = new ArrayList<>();

        for (Map<String, String> record : importRequest.getRecords()) {
            try {
                if (validateRecord(record, importRequest.getEntityName())) {
                    existingData.add(record);
                    importedCount++;
                } else {
                    errors.add("Validation failed for record: " + record.get("id"));
                }
            } catch (Exception e) {
                errors.add("Error importing record: " + e.getMessage());
            }
        }

        return createImportResponse(importedCount, errors);
    }

    private SOAPMessage handleBulkImport(Node operationNode) throws Exception {
        String rawXmlContent = getElementTextContent(operationNode, "Payload");

        if (rawXmlContent == null || rawXmlContent.trim().isEmpty()) {
            return createFaultResponse("BulkImport requires a Payload element");
        }

        Document payloadDoc = parseXmlString(rawXmlContent);
        if (payloadDoc == null) {
            return createFaultResponse("Failed to parse bulk import payload");
        }

        Element root = payloadDoc.getDocumentElement();
        int totalImported = 0;
        List<String> errors = new ArrayList<>();

        NodeList entityNodes = root.getChildNodes();
        for (int i = 0; i < entityNodes.getLength(); i++) {
            Node entityNode = entityNodes.item(i);
            if (entityNode.getNodeType() != Node.ELEMENT_NODE) continue;

            String entityName = entityNode.getNodeName();
            List<Map<String, String>> records = extractRecordsFromNode(entityNode);

            List<Map<String, String>> existingData = dataStore.computeIfAbsent(
                    entityName, k -> Collections.synchronizedList(new ArrayList<>()));

            for (Map<String, String> record : records) {
                try {
                    existingData.add(record);
                    totalImported++;
                } catch (Exception e) {
                    errors.add("Error in entity " + entityName + ": " + e.getMessage());
                }
            }
        }

        return createBulkImportResponse(totalImported, errors);
    }

    private SOAPMessage handleQueryData(Node operationNode) throws Exception {
        String entityName = getElementTextContent(operationNode, "EntityName");
        String filterField = getElementTextContent(operationNode, "FilterField");
        String filterValue = getElementTextContent(operationNode, "FilterValue");

        if (entityName == null) {
            return createFaultResponse("EntityName is required for QueryData");
        }

        List<Map<String, String>> data = dataStore.getOrDefault(entityName, Collections.emptyList());
        List<Map<String, String>> results;

        if (filterField != null && filterValue != null) {
            results = new ArrayList<>();
            for (Map<String, String> record : data) {
                if (filterValue.equals(record.get(filterField))) {
                    results.add(record);
                }
            }
        } else {
            results = new ArrayList<>(data);
        }

        return createQueryResponse(entityName, results);
    }

    private SOAPMessage handleTransformData(Node operationNode) throws Exception {
        String sourceEntity = getElementTextContent(operationNode, "SourceEntity");
        String targetEntity = getElementTextContent(operationNode, "TargetEntity");

        if (sourceEntity == null || targetEntity == null) {
            return createFaultResponse("SourceEntity and TargetEntity are required");
        }

        Node mappingsNode = getChildElement(operationNode, "FieldMappings");
        Map<String, String> fieldMappings = new LinkedHashMap<>();

        if (mappingsNode != null) {
            NodeList mappingNodes = mappingsNode.getChildNodes();
            for (int i = 0; i < mappingNodes.getLength(); i++) {
                Node mappingNode = mappingNodes.item(i);
                if (mappingNode.getNodeType() == Node.ELEMENT_NODE && "Mapping".equals(mappingNode.getLocalName())) {
                    String sourceField = getElementTextContent(mappingNode, "Source");
                    String targetField = getElementTextContent(mappingNode, "Target");
                    if (sourceField != null && targetField != null) {
                        fieldMappings.put(sourceField, targetField);
                    }
                }
            }
        }

        List<Map<String, String>> sourceData = dataStore.getOrDefault(sourceEntity, Collections.emptyList());
        List<Map<String, String>> transformedData = Collections.synchronizedList(new ArrayList<>());

        int transformedCount = 0;
        for (Map<String, String> sourceRecord : sourceData) {
            Map<String, String> targetRecord = new LinkedHashMap<>();
            for (Map.Entry<String, String> mapping : fieldMappings.entrySet()) {
                String value = sourceRecord.get(mapping.getKey());
                if (value != null) {
                    targetRecord.put(mapping.getValue(), value);
                }
            }
            if (!targetRecord.isEmpty()) {
                transformedData.add(targetRecord);
                transformedCount++;
            }
        }

        dataStore.put(targetEntity, transformedData);
        return createTransformResponse(transformedCount, sourceEntity, targetEntity);
    }

    private SOAPMessage handleValidateSchema(Node operationNode) throws Exception {
        String xmlContent = getElementTextContent(operationNode, "XmlContent");
        String entityName = getElementTextContent(operationNode, "EntityName");

        if (xmlContent == null) {
            return createFaultResponse("XmlContent is required for ValidateSchema");
        }

        Document doc = parseXmlString(xmlContent);
        List<String> validationErrors = new ArrayList<>();

        if (doc == null) {
            validationErrors.add("XML is not well-formed");
        } else {
            validateStructure(doc.getDocumentElement(), entityName, validationErrors, "");
        }

        return createValidationResponse(validationErrors.isEmpty(), validationErrors);
    }

