    private ImportRequest parseImportRequest(Node operationNode) {
        ImportRequest request = new ImportRequest();
        request.setEntityName(getElementTextContent(operationNode, "EntityName"));

        String batchId = getElementTextContent(operationNode, "BatchId");
        request.setBatchId(batchId != null ? batchId : UUID.randomUUID().toString());

        Node recordsNode = getChildElement(operationNode, "Records");
        if (recordsNode != null) {
            request.setRecords(extractRecordsFromNode(recordsNode));
        }

        return request;
    }

    private List<Map<String, String>> extractRecordsFromNode(Node parentNode) {
        List<Map<String, String>> records = new ArrayList<>();
        NodeList childNodes = parentNode.getChildNodes();

        for (int i = 0; i < childNodes.getLength(); i++) {
            Node childNode = childNodes.item(i);
            if (childNode.getNodeType() != Node.ELEMENT_NODE) continue;

            Map<String, String> record = new LinkedHashMap<>();
            extractFieldsRecursive(childNode, record, "");
            if (!record.isEmpty()) {
                records.add(record);
            }
        }

        return records;
    }

    private void extractFieldsRecursive(Node node, Map<String, String> record, String prefix) {
        // Extract attributes
        NamedNodeMap attributes = node.getAttributes();
        if (attributes != null) {
            for (int i = 0; i < attributes.getLength(); i++) {
                Node attr = attributes.item(i);
                String key = prefix.isEmpty() ? "@" + attr.getNodeName() : prefix + ".@" + attr.getNodeName();
                record.put(key, attr.getNodeValue());
            }
        }

        NodeList children = node.getChildNodes();
        boolean hasElementChildren = false;

        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                hasElementChildren = true;
                break;
            }
        }

        if (!hasElementChildren) {
            // Leaf node
            String textContent = node.getTextContent();
            if (textContent != null) {
                String key = prefix.isEmpty() ? node.getLocalName() : prefix + "." + node.getLocalName();
                record.put(key, textContent.trim());
            }
        } else {
            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.ELEMENT_NODE) {
                    String newPrefix = prefix.isEmpty() ? child.getLocalName() : prefix + "." + child.getLocalName();
                    // Check if this child has element children
                    boolean childHasElements = false;
                    NodeList grandChildren = child.getChildNodes();
                    for (int j = 0; j < grandChildren.getLength(); j++) {
                        if (grandChildren.item(j).getNodeType() == Node.ELEMENT_NODE) {
                            childHasElements = true;
                            break;
                        }
                    }
                    if (childHasElements) {
                        extractFieldsRecursive(child, record, newPrefix);
                    } else {
                        String textContent = child.getTextContent();
                        if (textContent != null) {
                            record.put(newPrefix, textContent.trim());
                        }
                    }
                }
            }
        }
    }

    private Document parseXmlString(String xmlContent) {
        try {
            DocumentBuilder builder = documentBuilderFactory.newDocumentBuilder();
            InputSource is = new InputSource(new StringReader(xmlContent));
            return builder.parse(is);
        } catch (ParserConfigurationException | SAXException | IOException e) {
            LOGGER.log(Level.WARNING, "Failed to parse XML string", e);
            return null;
        }
    }

    private void validateStructure(Element element, String entityName, List<String> errors, String path) {
        String currentPath = path.isEmpty() ? element.getTagName() : path + "/" + element.getTagName();

        if (element.getTagName() == null || element.getTagName().trim().isEmpty()) {
            errors.add("Empty element name at path: " + currentPath);
        }

        // Check for excessively deep nesting (protection against stack overflow)
        if (currentPath.split("/").length > 50) {
            errors.add("XML structure too deeply nested at path: " + currentPath);
            return;
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                validateStructure((Element) child, entityName, errors, currentPath);
            }
        }
    }

    private boolean validateRecord(Map<String, String> record, String entityName) {
        return record != null && !record.isEmpty();
    }

    // --- Element Access Helpers ---

    private Node getFirstChildElement(Node parent) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return children.item(i);
            }
        }
        return null;
    }

    private Node getChildElement(Node parent, String localName) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE &&
                    (localName.equals(child.getLocalName()) || localName.equals(child.getNodeName()))) {
                return child;
            }
        }
        return null;
    }

    private String getElementTextContent(Node parent, String localName) {
        Node child = getChildElement(parent, localName);
        if (child != null) {
            String text = child.getTextContent();
            return text != null ? text.trim() : null;
        }
        return null;
    }

