    private SOAPMessage createImportResponse(int importedCount, List<String> errors) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement responseElement = body.addChildElement("ImportDataResponse", "edi",
                "http://enterprise.integration/soap");
        responseElement.addChildElement("Status").addTextNode(errors.isEmpty() ? "SUCCESS" : "PARTIAL");
        responseElement.addChildElement("ImportedCount").addTextNode(String.valueOf(importedCount));

        if (!errors.isEmpty()) {
            SOAPElement errorsElement = responseElement.addChildElement("Errors");
            for (String error : errors) {
                errorsElement.addChildElement("Error").addTextNode(error);
            }
        }

        response.saveChanges();
        return response;
    }

    private SOAPMessage createBulkImportResponse(int totalImported, List<String> errors) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement responseElement = body.addChildElement("BulkImportResponse", "edi",
                "http://enterprise.integration/soap");
        responseElement.addChildElement("Status").addTextNode(errors.isEmpty() ? "SUCCESS" : "PARTIAL");
        responseElement.addChildElement("TotalImported").addTextNode(String.valueOf(totalImported));

        if (!errors.isEmpty()) {
            SOAPElement errorsElement = responseElement.addChildElement("Errors");
            for (String error : errors) {
                errorsElement.addChildElement("Error").addTextNode(error);
            }
        }

        response.saveChanges();
        return response;
    }

    private SOAPMessage createQueryResponse(String entityName, List<Map<String, String>> results) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement responseElement = body.addChildElement("QueryDataResponse", "edi",
                "http://enterprise.integration/soap");
        responseElement.addChildElement("EntityName").addTextNode(entityName);
        responseElement.addChildElement("ResultCount").addTextNode(String.valueOf(results.size()));

        SOAPElement recordsElement = responseElement.addChildElement("Records");
        for (Map<String, String> record : results) {
            SOAPElement recordElement = recordsElement.addChildElement("Record");
            for (Map.Entry<String, String> field : record.entrySet()) {
                recordElement.addChildElement("Field")
                        .addAttribute(response.getSOAPPart().getEnvelope().createName("name"), field.getKey())
                        .addTextNode(field.getValue());
            }
        }

        response.saveChanges();
        return response;
    }

    private SOAPMessage createTransformResponse(int transformedCount, String source, String target) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement responseElement = body.addChildElement("TransformDataResponse", "edi",
                "http://enterprise.integration/soap");
        responseElement.addChildElement("Status").addTextNode("SUCCESS");
        responseElement.addChildElement("TransformedCount").addTextNode(String.valueOf(transformedCount));
        responseElement.addChildElement("SourceEntity").addTextNode(source);
        responseElement.addChildElement("TargetEntity").addTextNode(target);

        response.saveChanges();
        return response;
    }

    private SOAPMessage createValidationResponse(boolean isValid, List<String> errors) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();

        SOAPElement responseElement = body.addChildElement("ValidateSchemaResponse", "edi",
                "http://enterprise.integration/soap");
        responseElement.addChildElement("IsValid").addTextNode(String.valueOf(isValid));

        if (!errors.isEmpty()) {
            SOAPElement errorsElement = responseElement.addChildElement("ValidationErrors");
            for (String error : errors) {
                errorsElement.addChildElement("Error").addTextNode(error);
            }
        }

        response.saveChanges();
        return response;
    }

    private SOAPMessage createFaultResponse(String message) throws Exception {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage response = factory.createMessage();
        SOAPBody body = response.getSOAPBody();
        SOAPFault fault = body.addFault();
        fault.setFaultString(message);
        fault.setFaultCode("Server");
        response.saveChanges();
        return response;
    }

